import React, { useState, useMemo } from 'react';

const theme = {
  colors: {
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    orange: '#fb923c',
    green: '#a3e635',
    purple: '#a78bfa',
    red: '#f43f5e',
  },
  font: "'JetBrains Mono', monospace",
};

const tokens = ['The', 'cat', 'sat', 'down'];
const n = tokens.length;

const rawScores = [
  [2.1, 0.8, -0.2, 0.5],
  [1.0, 2.4, 0.6, -0.3],
  [0.3, 0.9, 2.7, 1.1],
  [0.7, 0.2, 1.3, 2.9],
];

function softmaxRow(row) {
  const max = Math.max(...row);
  const exps = row.map(v => Math.exp(v - max));
  const sum = exps.reduce((a, b) => a + b, 0);
  return exps.map(e => e / sum);
}

function computeWeights(scores, mask) {
  return scores.map((row, i) => {
    const masked = row.map((s, j) => (mask[i][j] ? s + -1e9 : s));
    return softmaxRow(masked);
  });
}

function makeCausal() {
  const m = Array(n).fill(null).map(() => Array(n).fill(false));
  for (let i = 0; i < n; i++)
    for (let j = i + 1; j < n; j++) m[i][j] = true;
  return m;
}

function makeFull() {
  return Array(n).fill(null).map(() => Array(n).fill(false));
}

function makeWindow() {
  const m = Array(n).fill(null).map(() => Array(n).fill(true));
  for (let i = 0; i < n; i++)
    for (let j = Math.max(0, i - 1); j <= i; j++) m[i][j] = false;
  return m;
}

export default function App() {
  const [mask, setMask] = useState(makeCausal);
  const [selectedRow, setSelectedRow] = useState(0);
  const [hoveredCell, setHoveredCell] = useState(null);

  const weights = useMemo(() => computeWeights(rawScores, mask), [mask]);

  const toggleCell = (i, j) => {
    const newMask = mask.map(r => [...r]);
    newMask[i][j] = !newMask[i][j];
    if (newMask[i].every(v => v)) return;
    setMask(newMask);
  };

  const maskedCount = mask.flat().filter(v => v).length;

  const getInsight = () => {
    const isCausal = mask.every((row, i) =>
      row.every((v, j) => (j <= i ? !v : v))
    );
    const isFull = mask.every(row => row.every(v => !v));
    if (isFull)
      return 'Full attention: every token sees all others. No causal constraint -- useful for encoders (like BERT) but not for text generation.';
    if (isCausal)
      return 'Causal mask: each token only attends to itself and prior tokens. This preserves left-to-right causality, essential for autoregressive models like GPT.';
    const isWindow = mask.every((row, i) =>
      row.every((v, j) => {
        const inWindow = j >= Math.max(0, i - 1) && j <= i;
        return inWindow ? !v : v;
      })
    );
    if (isWindow)
      return 'Sliding window: each token attends to itself and the one before it. This limits context but reduces computation -- used in efficient transformers like Longformer.';
    return 'Custom mask: ' + maskedCount + ' of ' + (n * n) + ' positions blocked. Notice how softmax redistributes weight from masked to unmasked positions.';
  };

  const presetActive = (name) => {
    if (name === 'Causal') return mask.every((row, i) => row.every((v, j) => (j <= i ? !v : v)));
    if (name === 'Full') return mask.every(row => row.every(v => !v));
    if (name === 'Window') return mask.every((row, i) => row.every((v, j) => { const inW = j >= Math.max(0, i - 1) && j <= i; return inW ? !v : v; }));
    return false;
  };

  const cellSize = 68;
  const labelW = 52;

  return (
    <div style={{
      maxWidth: 600, margin: '0 auto', padding: 20,
      fontFamily: theme.font, background: theme.colors.background,
      color: theme.colors.text, minHeight: '100vh',
    }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 14 }}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 700 }}>Masked Self-Attention</div>
          <div style={{ fontSize: 11, color: theme.colors.textMuted, marginTop: 3 }}>
            Click cells to toggle mask on/off
          </div>
        </div>
        <div style={{ display: 'flex', gap: 5 }}>
          {[
            { label: 'Causal', fn: () => setMask(makeCausal()) },
            { label: 'Full', fn: () => setMask(makeFull()) },
            { label: 'Window', fn: () => setMask(makeWindow()) },
          ].map(p => (
            <button key={p.label} onClick={p.fn} style={{
              padding: '5px 10px',
              background: presetActive(p.label) ? 'rgba(139,92,246,0.2)' : theme.colors.surfaceAlt,
              border: '1px solid ' + (presetActive(p.label) ? 'rgba(139,92,246,0.5)' : theme.colors.border),
              borderRadius: 6, color: presetActive(p.label) ? theme.colors.purple : theme.colors.textSecondary,
              fontFamily: theme.font, fontSize: 11, cursor: 'pointer',
              transition: 'all 0.2s ease',
            }}>{p.label}</button>
          ))}
        </div>
      </div>

      {/* Formula */}
      <div style={{
        textAlign: 'center', marginBottom: 12, fontSize: 11,
        color: theme.colors.textMuted, letterSpacing: 0.3,
      }}>
        <span style={{ color: theme.colors.blue }}>score = QK'/sqrt(d)</span>
        <span> -> </span>
        <span style={{ color: theme.colors.red }}>+ mask</span>
        <span> -> </span>
        <span style={{ color: theme.colors.green }}>softmax</span>
        <span> -> </span>
        <span style={{ color: theme.colors.yellow }}>weights</span>
      </div>

      {/* Attention Grid */}
      <div style={{
        background: theme.colors.surface, borderRadius: 12, padding: 16,
        border: '1px solid ' + theme.colors.border, marginBottom: 12,
      }}>
        {/* Keys label */}
        <div style={{
          display: 'flex', alignItems: 'center', marginBottom: 6,
        }}>
          <div style={{ width: labelW }} />
          <div style={{
            flex: 1, textAlign: 'center', fontSize: 10,
            color: theme.colors.textMuted, letterSpacing: 1,
          }}>KEYS</div>
        </div>

        {/* Column headers */}
        <div style={{ display: 'flex', marginLeft: labelW + 2, marginBottom: 4 }}>
          {tokens.map((t, j) => (
            <div key={j} style={{
              width: cellSize, textAlign: 'center',
              fontSize: 12, color: theme.colors.blue, fontWeight: 600,
            }}>{t}</div>
          ))}
        </div>

        {/* Grid rows */}
        <div style={{ display: 'flex' }}>
          {/* Queries label */}
          <div style={{
            width: 14, display: 'flex', alignItems: 'center', justifyContent: 'center',
            marginRight: 2,
          }}>
            <div style={{
              transform: 'rotate(-90deg)', fontSize: 10,
              color: theme.colors.textMuted, letterSpacing: 1, whiteSpace: 'nowrap',
            }}>QUERIES</div>
          </div>
          <div>
            {tokens.map((token, i) => (
              <div key={i} style={{ display: 'flex', alignItems: 'center', marginBottom: 2 }}>
                <div
                  onClick={() => setSelectedRow(i)}
                  style={{
                    width: labelW - 16, textAlign: 'right', paddingRight: 6,
                    fontSize: 12, cursor: 'pointer',
                    color: selectedRow === i ? theme.colors.yellow : theme.colors.pink,
                    fontWeight: selectedRow === i ? 700 : 500,
                    transition: 'all 0.2s ease',
                  }}
                >{token}</div>
                {tokens.map((_, j) => {
                  const isMasked = mask[i][j];
                  const w = weights[i][j];
                  const isHovered = hoveredCell && hoveredCell[0] === i && hoveredCell[1] === j;
                  const isSelectedRowCell = selectedRow === i;
                  return (
                    <div
                      key={j}
                      onClick={() => toggleCell(i, j)}
                      onMouseEnter={() => setHoveredCell([i, j])}
                      onMouseLeave={() => setHoveredCell(null)}
                      style={{
                        width: cellSize - 4, height: cellSize - 4, margin: 2,
                        borderRadius: 8, display: 'flex', flexDirection: 'column',
                        alignItems: 'center', justifyContent: 'center', cursor: 'pointer',
                        background: isMasked
                          ? (isHovered ? 'rgba(244,63,94,0.15)' : 'rgba(244,63,94,0.06)')
                          : 'rgba(56,189,248,' + (0.04 + Math.min(w, 1) * 0.5) + ')',
                        border: '1px solid ' + (
                          isHovered ? 'rgba(255,255,255,0.25)'
                          : isMasked ? 'rgba(244,63,94,0.18)'
                          : isSelectedRowCell ? 'rgba(251,191,36,0.35)'
                          : 'rgba(56,189,248,0.12)'
                        ),
                        transition: 'all 0.3s ease',
                        transform: isHovered ? 'scale(1.05)' : 'scale(1)',
                      }}
                    >
                      {isMasked ? (
                        <>
                          <div style={{ fontSize: 18, color: theme.colors.red, opacity: 0.45, lineHeight: 1 }}>X</div>
                          <div style={{ fontSize: 9, color: theme.colors.textMuted, marginTop: 1 }}>-inf</div>
                        </>
                      ) : (
                        <>
                          <div style={{
                            fontSize: 15, fontWeight: 700, lineHeight: 1,
                            color: w > 0.45 ? '#fff' : theme.colors.blue,
                          }}>{w < 0.005 ? '~0' : w.toFixed(2)}</div>
                          <div style={{ fontSize: 9, color: theme.colors.textMuted, marginTop: 2 }}>
                            s={rawScores[i][j] >= 0 ? '+' : ''}{rawScores[i][j].toFixed(1)}
                          </div>
                        </>
                      )}
                    </div>
                  );
                })}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Attention Distribution Bar Chart */}
      <div style={{
        background: theme.colors.surface, borderRadius: 12, padding: 16,
        border: '1px solid ' + theme.colors.border, marginBottom: 12,
      }}>
        <div style={{ fontSize: 11, color: theme.colors.textSecondary, marginBottom: 12 }}>
          Attention distribution for query{' '}
          <span style={{ color: theme.colors.yellow, fontWeight: 700 }}>
            "{tokens[selectedRow]}"
          </span>
          <span style={{ color: theme.colors.textMuted }}> (row {selectedRow})</span>
        </div>

        <div style={{ display: 'flex', gap: 10, alignItems: 'flex-end', height: 72, marginBottom: 4 }}>
          {tokens.map((t, j) => {
            const w = weights[selectedRow][j];
            const isMasked = mask[selectedRow][j];
            const barH = isMasked ? 2 : Math.max(3, w * 64);
            return (
              <div key={j} style={{
                flex: 1, display: 'flex', flexDirection: 'column',
                alignItems: 'center', justifyContent: 'flex-end', height: '100%',
              }}>
                <div style={{
                  fontSize: 12, fontWeight: 700, marginBottom: 4,
                  color: isMasked ? theme.colors.textMuted : theme.colors.blue,
                  transition: 'all 0.3s ease',
                }}>
                  {isMasked ? '0%' : (w * 100).toFixed(0) + '%'}
                </div>
                <div style={{
                  width: '70%', maxWidth: 56, height: barH,
                  background: isMasked
                    ? 'rgba(244,63,94,0.15)'
                    : 'linear-gradient(180deg, rgba(56,189,248,' + (0.4 + w * 0.6) + '), rgba(56,189,248,' + (0.15 + w * 0.3) + '))',
                  borderRadius: '4px 4px 2px 2px',
                  transition: 'all 0.4s cubic-bezier(0.4,0,0.2,1)',
                }} />
              </div>
            );
          })}
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          {tokens.map((t, j) => (
            <div key={j} style={{
              flex: 1, textAlign: 'center', fontSize: 11,
              color: mask[selectedRow][j] ? theme.colors.textMuted : theme.colors.textSecondary,
            }}>{t}</div>
          ))}
        </div>
      </div>

      {/* Computation detail for hovered cell */}
      {hoveredCell && (
        <div style={{
          background: theme.colors.surfaceAlt, borderRadius: 8, padding: '8px 12px',
          border: '1px solid ' + theme.colors.border, marginBottom: 10,
          fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.7,
        }}>
          <span style={{ color: theme.colors.pink }}>{tokens[hoveredCell[0]]}</span>
          <span> -> </span>
          <span style={{ color: theme.colors.blue }}>{tokens[hoveredCell[1]]}</span>
          <span>: raw score = {rawScores[hoveredCell[0]][hoveredCell[1]].toFixed(2)}</span>
          {mask[hoveredCell[0]][hoveredCell[1]] ? (
            <span style={{ color: theme.colors.red }}> + (-inf) = masked out. Weight = 0 after softmax.</span>
          ) : (
            <span style={{ color: theme.colors.green }}>
              {' '}-> softmax -> weight = {weights[hoveredCell[0]][hoveredCell[1]].toFixed(3)}
            </span>
          )}
        </div>
      )}

      {/* Insight */}
      <div style={{
        padding: '10px 14px', background: theme.colors.surface,
        border: '1px solid ' + theme.colors.border, borderRadius: 8,
        fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.7,
      }}>
        <strong style={{ color: theme.colors.yellow }}>Insight: </strong>
        {getInsight()}
      </div>
    </div>
  );
}
